sentence = input().split(' ')
words = {word for word in sentence if sentence.count(word) > 1}

print(len(sentence))
if len(words) < 1:
    print("Only unique words")
for word in sentence:
    if word in words:
        print(word + ": " + str(sentence.count(word)))
        words.remove(word)
